83	/// Read an env-file value or None if absent. Mirrors pristine's helper —
84	/// kept local to avoid coupling canonical-establish to pristine-lifecycle.
85	fn rbtdrk_read_env_value(path: &Path, key: &str) -> Option<String> {
86	    let content = std::fs::read_to_string(path).ok()?;
87	    let prefix = format!("{}=", key);
88	    for line in content.lines() {
89	        let trimmed = line.trim_start();
90	        if trimmed.starts_with('#') {
91	            continue;
92	        }
93	        if let Some(rest) = trimmed.strip_prefix(&prefix) {
94	            return Some(rest.to_string());
95	        }
96	    }
97	    None
98	}
