229	/// Pick the next free moniker for `family_stem` by walking the depot_list
230	/// invocation's BURV output dir for `<family>NNNNNN.depot` files. Returns
231	/// `<family>RBTDRK_FAMILY_NUMERIC_FLOOR` when no matching files exist.
232	fn rbtdrk_pick_next_moniker(
233	    list_result: &rbtdri_InvokeResult,
234	    family_stem: &str,
235	) -> Result<String, String> {
236	    let dir = list_result.burv_output.join(RBTDRI_BURV_OUTPUT_SUBDIR);
237	    let entries = match std::fs::read_dir(&dir) {
238	        Ok(e) => e,
239	        Err(_) => {
240	            return Ok(format!("{}{}", family_stem, RBTDRK_FAMILY_NUMERIC_FLOOR));
241	        }
242	    };
243	    let suffix_ext = format!(".{}", RBTDRK_FACT_EXT_DEPOT);
244	    let mut max_suffix: Option<u32> = None;
245	    for entry in entries.flatten() {
246	        let name = match entry.file_name().into_string() {
247	            Ok(n) => n,
248	            Err(_) => continue,
249	        };
250	        let stem = match name.strip_suffix(&suffix_ext) {
251	            Some(s) => s,
252	            None => continue,
253	        };
254	        let numeric = match stem.strip_prefix(family_stem) {
255	            Some(s) => s,
256	            None => continue,
257	        };
258	        if numeric.len() != RBTDRK_FAMILY_NUMERIC_WIDTH {
259	            continue;
260	        }
261	        let parsed: u32 = match numeric.parse() {
262	            Ok(n) => n,
263	            Err(_) => continue,
264	        };
265	        max_suffix = Some(max_suffix.map_or(parsed, |m| m.max(parsed)));
266	    }
267	    let next = match max_suffix {
268	        Some(m) => m + 1,
269	        None => RBTDRK_FAMILY_NUMERIC_FLOOR,
270	    };
271	    Ok(format!("{}{}", family_stem, next))
272	}
